input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=strategic -p '
{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "elasticsearch",
            "env": [
              {
                "name": "ES_LOG_STYLE",
                "value": "file"
              }
            ],
            "volumeMounts": [
              {
                "name": "es-logs",
                "mountPath": "/usr/share/elasticsearch/logs"
              }
            ]
          },
          {
            "name": "metricbeat",
            "image": "docker.elastic.co/beats/metricbeat:7.17.9",
            "args": ["-e"],
            "resources": {
              "requests": {"cpu": "100m", "memory": "128Mi"},
              "limits": {"cpu": "200m", "memory": "256Mi"}
            },
            "volumeMounts": [
              {
                "name": "metricbeat-config",
                "mountPath": "/usr/share/metricbeat/metricbeat.yml",
                "subPath": "metricbeat.yml",
                "readOnly": true
              },
              {
                "name": "http-certs",
                "mountPath": "/certs",
                "readOnly": true
              }
            ]
          },
          {
            "name": "filebeat",
            "image": "docker.elastic.co/beats/filebeat:7.17.9",
            "args": ["-e"],
            "resources": {
              "requests": {"cpu": "100m", "memory": "128Mi"},
              "limits": {"cpu": "200m", "memory": "256Mi"}
            },
            "volumeMounts": [
              {
                "name": "filebeat-config",
                "mountPath": "/usr/share/filebeat/filebeat.yml",
                "subPath": "filebeat.yml",
                "readOnly": true
              },
              {
                "name": "es-logs",
                "mountPath": "/var/log/elasticsearch",
                "readOnly": true
              }
            ]
          }
        ],
        "volumes": [
          {
            "name": "es-logs",
            "emptyDir": {}
          },
          {
            "name": "metricbeat-config",
            "configMap": {
              "name": "metricbeat-config"
            }
          },
          {
            "name": "filebeat-config",
            "configMap": {
              "name": "filebeat-config"
            }
          }
        ]
      }
    }
  }
}'
